parameters.jsCode:
// Extract the generated article text from OpenAI response
const response = $input.first().json;
const articleRaw = response.choices[0].message.content;

// Split out TAGS line
const lines = articleRaw.split('\n');
const tagsLine = lines.find(l => l.startsWith('TAGS:'));
const tags = tagsLine 
  ? tagsLine.replace('TAGS:', '').trim().split(',').map(t => t.trim())
  : ['devops', 'kubernetes', 'cloud', 'tutorial'];

// Remove TAGS line from article body
const article = lines.filter(l => !l.startsWith('TAGS:')).join('\n').trim();

// Extract title from first H1
const titleMatch = article.match(/^#\s+(.+)$/m);
const title = titleMatch ? titleMatch[1].trim() : 'Technical Article';

// Word count
const wordCount = article.split(/\s+/).length;

// Get topic id from earlier node
const topicId = $('Mark Topic as Processing').first().json[0].id;
const topic   = $('Mark Topic as Processing').first().json[0].topic;

return [
  {
    json: {
      topic_id:   topicId,
      topic:      topic,
      title:      title,
      article:    article,
      tags:       tags,
      word_count: wordCount,
      generated_at: new Date().toISOString()
    }
  }
];

